args.query:
SELECT "Patient_description", COALESCE("histological_type", "Histological_Type", "histologicalType") AS hist_type, COALESCE("vital_status", "Vital_Status", "vitalStatus") AS vital_status, COALESCE("acronym", "Acronym", "cancer_type_acronym", "Cancer_Type_Acronym") AS acronym
FROM clinical_info
WHERE COALESCE("acronym", "Acronym", "cancer_type_acronym", "Cancer_Type_Acronym") = 'BRCA';

